import{_ as n,c as a,o as p,aj as t}from"./chunks/framework.CynFBi0q.js";const h=JSON.parse('{"title":"第15章 AI 时代的产品经理","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-product/chapter_15.md","filePath":"handbook/ai-product/chapter_15.md","lastUpdated":1782008855000}'),l={name:"handbook/ai-product/chapter_15.md"};function e(r,s,i,d,b,c){return p(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="第15章-ai-时代的产品经理" tabindex="-1">第15章 AI 时代的产品经理 <a class="header-anchor" href="#第15章-ai-时代的产品经理" aria-label="Permalink to “第15章 AI 时代的产品经理”">​</a></h1><p>2023年大模型爆发后，所有人都在问同一个问题：&quot;产品经理会被AI替代吗？&quot;我的答案是：不会被替代，但会被&quot;会用AI的产品经理&quot;替代。</p><p>我是怕浪猫，这一章不讲AI技术原理（你要的不是这个），只讲AI时代产品经理的能力升级路径。</p><h2 id="_15-1-ai-对产品经理的影响" tabindex="-1">15.1 AI 对产品经理的影响 <a class="header-anchor" href="#_15-1-ai-对产品经理的影响" aria-label="Permalink to “15.1 AI 对产品经理的影响”">​</a></h2><h3 id="_15-1-1-ai-能替代产品经理的哪些工作" tabindex="-1">15.1.1 AI 能替代产品经理的哪些工作 <a class="header-anchor" href="#_15-1-1-ai-能替代产品经理的哪些工作" aria-label="Permalink to “15.1.1 AI 能替代产品经理的哪些工作”">​</a></h3><p>AI能替代的：重复性、规则性、可描述的工作。</p><p><strong>AI能替代的具体工作</strong></p><table tabindex="0"><thead><tr><th>工作类型</th><th>AI能做什么</th><th>示例</th><th>效率提升</th></tr></thead><tbody><tr><td>竞品功能对比</td><td>自动抓取竞品功能并对比</td><td>&quot;帮我对比微信和钉钉的群聊功能&quot;</td><td>5-10倍</td></tr><tr><td>用户反馈分类</td><td>自动分类和归纳反馈</td><td>把1000条用户反馈按主题分类</td><td>10-20倍</td></tr><tr><td>数据报表生成</td><td>自动生成数据分析报告</td><td>&quot;分析上周的用户留存数据并生成报告&quot;</td><td>3-5倍</td></tr><tr><td>PRD初稿撰写</td><td>根据需求描述生成PRD框架</td><td>&quot;帮我写一个搜索功能的PRD框架&quot;</td><td>3-5倍</td></tr><tr><td>原型线框图</td><td>根据描述生成线框图</td><td>&quot;画一个电商首页的线框图&quot;</td><td>2-3倍</td></tr><tr><td>会议纪要整理</td><td>自动提取关键决策和待办</td><td>录音转文字后自动生成纪要</td><td>5-8倍</td></tr><tr><td>用户画像梳理</td><td>从数据中归纳典型用户特征</td><td>&quot;根据这批用户数据生成用户画像&quot;</td><td>3-5倍</td></tr></tbody></table><p>怕浪猫要提醒你一个关键点：AI替代的不是&quot;工作&quot;，是&quot;工作中的重复部分&quot;。竞品分析AI能帮你做表格，但&quot;判断竞品哪个功能值得学&quot;这件事，AI做不了。数据报表AI能帮你生成，但&quot;从数据中发现商业机会&quot;这件事，AI也做不了。区分清楚这两件事，你就不会焦虑了。</p><p><strong>AI不能替代的：创造性、判断性、责任性的工作</strong></p><table tabindex="0"><thead><tr><th>工作类型</th><th>为什么AI不能替代</th><th>示例</th></tr></thead><tbody><tr><td>产品方向决策</td><td>需要综合判断和商业嗅觉</td><td>&quot;我们应该做社区功能吗？&quot;</td></tr><tr><td>用户体验设计</td><td>需要深度理解用户</td><td>&quot;这个交互设计用户会觉得好用吗？&quot;</td></tr><tr><td>跨团队协调</td><td>需要人情世故和沟通技巧</td><td>说服研发接受紧排期</td></tr><tr><td>产品价值观决策</td><td>需要道德判断</td><td>&quot;这个功能会不会伤害用户？&quot;</td></tr><tr><td>创新性需求洞察</td><td>需要从模糊信号中发现机会</td><td>&quot;用户说的和用户想要的不是一回事&quot;</td></tr><tr><td>战略级取舍</td><td>需要承担决策后果</td><td>&quot;砍掉这个功能会影响多少人？&quot;</td></tr></tbody></table><h3 id="_15-1-2-ai-时代产品经理的新能力要求" tabindex="-1">15.1.2 AI 时代产品经理的新能力要求 <a class="header-anchor" href="#_15-1-2-ai-时代产品经理的新能力要求" aria-label="Permalink to “15.1.2 AI 时代产品经理的新能力要求”">​</a></h3><p>AI时代的产品经理，需要掌握五类新能力。前三类大家可能已经听过，后两类是怕浪猫觉得被严重低估的。</p><p><strong>能力一：AI工具的使用能力</strong></p><p>不是&quot;会用ChatGPT聊天&quot;，而是&quot;能用AI提升工作效率&quot;。</p><p>具体表现：</p><ul><li>用AI辅助写PRD：先让AI生成框架，再人工精修</li><li>用AI做竞品分析：让AI帮你整理竞品功能的对比表格</li><li>用AI生成原型：用AI工具（如Galileo AI）快速生成界面原型</li><li>用AI辅助数据分析：让AI帮你写SQL查询、生成图表</li></ul><p>怕浪猫的经验是：AI工具的使用能力不是&quot;会用多少个工具&quot;，而是&quot;知道什么时候该用什么工具，以及怎么问出好问题&quot;。同一个ChatGPT，有人只能聊天，有人能拿它写完整的产品方案。差距不在工具，在用法。</p><p><strong>能力二：AI产品的设计能力</strong></p><p>AI时代会出现全新的产品形态。产品经理需要理解AI的能力边界和限制。</p><p>AI产品的设计要点：</p><ul><li>不确定性管理：AI的输出是不确定的，产品设计要考虑&quot;AI答错了怎么办&quot;</li><li>反馈机制：AI需要用户的反馈来改进，产品要设计便捷的反馈入口</li><li>透明度：AI做了什么决策，要告诉用户（至少是让用户知道&quot;这是AI生成的&quot;）</li><li>渐进式信任：用户对AI的信任是逐步建立的，产品要设计从低风险到高风险的使用路径</li><li>降级方案：当AI服务不可用或输出异常时，产品必须有可用的降级方案</li></ul><p><strong>能力三：AI伦理与风险管理能力</strong></p><p>AI产品会带来新的风险：隐私泄露、算法偏见、错误信息传播。</p><p>产品经理需要具备：</p><ul><li>数据隐私意识：用户数据怎么用、怎么保护</li><li>算法公平性意识：AI的决策是否公平，有没有歧视某些群体</li><li>内容安全责任：AI生成的内容谁来负责</li><li>合规意识：国内外AI相关法规的最新要求（比如欧盟AI法案、中国生成式AI管理办法）</li></ul><p><strong>能力四：提示词工程能力</strong></p><p>这是怕浪猫认为AI时代产品经理最被低估的能力。为什么？因为AI产品的核心逻辑就是&quot;输入Prompt，输出结果&quot;。产品经理如果不懂Prompt工程，就无法设计好AI产品，也无法高效使用AI工具。</p><p><strong>Prompt设计的核心原则：</strong></p><table tabindex="0"><thead><tr><th>原则</th><th>说明</th><th>错误示例</th><th>正确示例</th></tr></thead><tbody><tr><td>明确性</td><td>指令要具体，不要模糊</td><td>&quot;帮我分析一下&quot;</td><td>&quot;请从功能完整度、用户体验、商业化三个维度分析&quot;</td></tr><tr><td>结构性</td><td>用结构化格式组织Prompt</td><td>大段文字堆砌</td><td>用编号、分点、分隔符组织内容</td></tr><tr><td>上下文</td><td>提供足够的背景信息</td><td>&quot;写个PRD&quot;</td><td>&quot;我正在做一个面向C端的社交App，日活50万，现在要增加短视频功能，请写PRD&quot;</td></tr><tr><td>示例引导</td><td>给出期望的输出示例</td><td>不给示例</td><td>&quot;输出格式参考：1.功能名称 2.用户场景 3.验收标准&quot;</td></tr><tr><td>约束边界</td><td>明确告诉AI什么不要做</td><td>不设边界</td><td>&quot;不要超过500字，不要使用技术术语&quot;</td></tr></tbody></table><p><strong>结构化Prompt的标准模板：</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一个[具体角色]，擅长[具体能力]。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>请完成以下任务：[具体任务描述]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 背景</span></span>
<span class="line"><span>[提供上下文信息]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 要求</span></span>
<span class="line"><span>1. [要求1]</span></span>
<span class="line"><span>2. [要求2]</span></span>
<span class="line"><span>3. [要求3]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出格式</span></span>
<span class="line"><span>[描述期望的输出格式，或给出示例]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 约束</span></span>
<span class="line"><span>[明确边界和限制条件]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><p><strong>高级Prompt技巧：</strong></p><p>Few-shot（少样本示例）：给AI几个示例，让它理解你想要的输出模式。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>请根据用户反馈提取需求，参考以下示例：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>示例1：</span></span>
<span class="line"><span>用户反馈：&quot;搜索结果总是不相关&quot;</span></span>
<span class="line"><span>提取需求：搜索精准度优化，需改进搜索算法和相关度排序</span></span>
<span class="line"><span></span></span>
<span class="line"><span>示例2：</span></span>
<span class="line"><span>用户反馈：&quot;页面加载太慢了，等了5秒&quot;</span></span>
<span class="line"><span>提取需求：页面加载性能优化，目标加载时间&lt;2秒</span></span>
<span class="line"><span></span></span>
<span class="line"><span>现在请提取：</span></span>
<span class="line"><span>用户反馈：&quot;[你的反馈内容]&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>Chain-of-Thought（思维链）：让AI逐步推理，而不是直接给结论。对于复杂分析类任务特别有效。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>请分析这个功能是否值得做，按以下步骤推理：</span></span>
<span class="line"><span>1. 先分析用户需求强度：这个功能解决了什么问题？有多少用户有这个问题？</span></span>
<span class="line"><span>2. 再分析商业价值：这个功能能带来什么商业收益？</span></span>
<span class="line"><span>3. 然后分析技术成本：实现这个功能需要多少开发资源？</span></span>
<span class="line"><span>4. 最后综合判断：给出你的结论和理由</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>怕浪猫的实战心得：Prompt工程不是一次写对的，而是反复调试出来的。每次让AI输出后，看哪里不满意，修改Prompt再试。一般一个高质量Prompt需要3-5轮迭代。把你调试好的Prompt存下来，形成自己的Prompt库，这就是你的效率杠杆。</p><p><strong>能力五：AI产品评估能力</strong></p><p>AI产品和传统产品最大的区别是：传统产品的功能是确定性的——点了按钮一定有响应；AI产品的输出是概率性的——同样的问题可能得到不同的回答。这意味着你需要一套全新的评估体系。</p><p><strong>AI产品评估的三个层次：</strong></p><table tabindex="0"><thead><tr><th>评估层次</th><th>评估什么</th><th>核心指标</th><th>评估方法</th></tr></thead><tbody><tr><td>模型能力层</td><td>AI模型本身的能力</td><td>准确率、召回率、F1值</td><td>标注数据集评测</td></tr><tr><td>产品体验层</td><td>用户使用AI产品的体验</td><td>满意度、采纳率、修正率</td><td>A/B测试、用户访谈</td></tr><tr><td>业务价值层</td><td>AI产品对业务的影响</td><td>转化率、留存率、效率提升</td><td>前后对比、归因分析</td></tr></tbody></table><p><strong>AI产品核心评估指标体系：</strong></p><table tabindex="0"><thead><tr><th>指标类别</th><th>具体指标</th><th>计算方式</th><th>说明</th></tr></thead><tbody><tr><td>输出质量</td><td>准确率</td><td>正确输出/总输出</td><td>AI回答正确的比例</td></tr><tr><td>输出质量</td><td>相关性评分</td><td>人工评分1-5</td><td>输出与问题的相关程度</td></tr><tr><td>输出质量</td><td>完整性评分</td><td>人工评分1-5</td><td>输出是否覆盖了问题的所有方面</td></tr><tr><td>用户体验</td><td>采纳率</td><td>采纳AI建议次数/总建议次数</td><td>用户接受AI输出的比例</td></tr><tr><td>用户体验</td><td>修正率</td><td>用户修改AI输出的比例</td><td>修正率越低越好</td></tr><tr><td>用户体验</td><td>首次满意率</td><td>不修改直接使用的比例</td><td>一次性满意的占比</td></tr><tr><td>效率指标</td><td>平均响应时间</td><td>从提问到获得回答的时间</td><td>含模型推理时间和网络延迟</td></tr><tr><td>效率指标</td><td>任务完成时间</td><td>用户完成任务的总时间</td><td>对比有AI和没AI的差异</td></tr><tr><td>安全指标</td><td>有害输出率</td><td>有害输出/总输出</td><td>AI产生不当内容的比例</td></tr><tr><td>安全指标</td><td>幻觉率</td><td>事实错误输出/总输出</td><td>AI编造信息的比例</td></tr></tbody></table><p>怕浪猫提醒：评估AI产品时，不要只看模型层面的准确率，更要看产品层面的采纳率和业务层面的价值指标。一个准确率95%的AI功能，如果用户采纳率只有30%，说明产品体验有问题——可能AI的输出格式不好用，可能用户不信任AI，可能AI在关键场景上表现不好。评估是手段，改进才是目的。</p><h2 id="_15-2-ai-工具辅助产品设计" tabindex="-1">15.2 AI 工具辅助产品设计 <a class="header-anchor" href="#_15-2-ai-工具辅助产品设计" aria-label="Permalink to “15.2 AI 工具辅助产品设计”">​</a></h2><h3 id="_15-2-1-用-ai-辅助需求分析" tabindex="-1">15.2.1 用 AI 辅助需求分析 <a class="header-anchor" href="#_15-2-1-用-ai-辅助需求分析" aria-label="Permalink to “15.2.1 用 AI 辅助需求分析”">​</a></h3><p><strong>场景一：从用户反馈中提取需求</strong></p><p>传统方法：人工阅读1000条用户反馈，提取高频需求。耗时：2-3天。</p><p>AI辅助方法：把1000条反馈输入AI，让AI提取高频需求并分类。耗时：10分钟。</p><p>Prompt模板：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一个资深产品经理，擅长从用户反馈中提取有价值的需求洞察。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>请分析以下用户反馈，提取需求并分类。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 用户反馈</span></span>
<span class="line"><span>[粘贴用户反馈内容，每条一行]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 要求</span></span>
<span class="line"><span>1. 按主题分类（功能请求/体验问题/Bug报告/性能问题/其他）</span></span>
<span class="line"><span>2. 每个类别提取高频关键词（出现3次以上的）</span></span>
<span class="line"><span>3. 给出优先级建议（P0紧急/P1重要/P2一般/P3低优），优先级基于：</span></span>
<span class="line"><span>   - 出现频率（提到次数越多越优先）</span></span>
<span class="line"><span>   - 影响范围（影响多少用户）</span></span>
<span class="line"><span>   - 业务影响（对核心指标的影响程度）</span></span>
<span class="line"><span>4. 每个需求给出一句话描述和对应的原始反馈条数</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出格式</span></span>
<span class="line"><span>| 分类 | 需求描述 | 高频关键词 | 出现次数 | 优先级 |</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><p>输出示例：</p><table tabindex="0"><thead><tr><th>分类</th><th>需求描述</th><th>高频关键词</th><th>出现次数</th><th>优先级</th></tr></thead><tbody><tr><td>体验问题</td><td>搜索结果不精准</td><td>搜索、不准、找不到</td><td>87</td><td>P0</td></tr><tr><td>功能请求</td><td>支持夜间模式</td><td>夜间、暗黑、护眼</td><td>63</td><td>P1</td></tr><tr><td>Bug报告</td><td>分享图片失败</td><td>分享、图片、失败</td><td>45</td><td>P0</td></tr><tr><td>性能问题</td><td>页面加载慢</td><td>加载、卡顿、慢</td><td>38</td><td>P1</td></tr><tr><td>功能请求</td><td>增加收藏功能</td><td>收藏、保存、标记</td><td>31</td><td>P2</td></tr></tbody></table><p><strong>场景二：竞品功能对比</strong></p><p>传统方法：下载竞品App，手动截图对比功能。耗时：1-2天。</p><p>AI辅助方法：让AI自动对比。耗时：30分钟。</p><p>Prompt模板：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一个产品竞品分析专家，擅长系统性对比产品的功能差异。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>请对比以下产品的核心功能差异。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 产品信息</span></span>
<span class="line"><span>产品A：[产品名称]，[一句话描述定位]，核心功能：[列出核心功能]</span></span>
<span class="line"><span>产品B：[产品名称]，[一句话描述定位]，核心功能：[列出核心功能]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 分析维度</span></span>
<span class="line"><span>1. 功能完整度对比（谁的功能更全面）</span></span>
<span class="line"><span>2. 用户体验对比（谁的体验更流畅）</span></span>
<span class="line"><span>3. 差异化功能（各有什么独特功能）</span></span>
<span class="line"><span>4. 商业化对比（谁的变现能力更强）</span></span>
<span class="line"><span>5. 技术实现难度（如果我们要补齐差距，难度如何）</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出格式</span></span>
<span class="line"><span>先输出一个功能对比表格，再输出一段分析总结（不超过300字），最后给出3条可落地的建议。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><p><strong>场景三：需求优先级排序</strong></p><p>这是怕浪猫觉得AI用得最好的场景之一。当你有一堆需求不知道先做哪个时，让AI帮你用RICE模型排序。</p><p>Prompt模板：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一个产品经理，擅长用RICE模型进行需求优先级排序。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>请用RICE模型对以下需求进行排序。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 需求列表</span></span>
<span class="line"><span>1. [需求1]</span></span>
<span class="line"><span>2. [需求2]</span></span>
<span class="line"><span>3. [需求3]</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span># RICE评分标准</span></span>
<span class="line"><span>- Reach（覆盖面）：1-10分，影响多少用户</span></span>
<span class="line"><span>- Impact（影响度）：0.25x（微小）/ 0.5x（低）/ 1x（中）/ 2x（高）/ 3x（巨大）</span></span>
<span class="line"><span>- Confidence（信心度）：50%（低）/ 80%（中）/ 100%（高）</span></span>
<span class="line"><span>- Effort（工作量）：预估人月</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出格式</span></span>
<span class="line"><span>| 需求 | Reach | Impact | Confidence | Effort | RICE得分 | 排名 |</span></span>
<span class="line"><span>| 需求1 | 8 | 2x | 80% | 2人月 | 6.4 | 1 |</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最后给出排序建议和理由（200字以内）。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div><p><strong>场景四：用户访谈提纲生成</strong></p><p>传统方法：根据经验手写访谈提纲，容易遗漏关键问题。耗时：1-2小时。</p><p>AI辅助方法：让AI根据产品目标生成结构化访谈提纲。耗时：5分钟。</p><p>Prompt模板：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一个用户研究专家，擅长设计深入的用户访谈提纲。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>请为以下产品功能设计用户访谈提纲。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 产品背景</span></span>
<span class="line"><span>产品：[产品名称]</span></span>
<span class="line"><span>功能：[要验证的功能]</span></span>
<span class="line"><span>目标：[访谈要验证什么假设]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 要求</span></span>
<span class="line"><span>1. 设计8-10个问题</span></span>
<span class="line"><span>2. 按以下结构组织：</span></span>
<span class="line"><span>   - 破冰问题（1-2个，让用户放松）</span></span>
<span class="line"><span>   - 行为探索（3-4个，了解用户现有行为）</span></span>
<span class="line"><span>   - 需求验证（2-3个，验证我们的假设）</span></span>
<span class="line"><span>   - 开放收集（1-2个，让用户自由表达）</span></span>
<span class="line"><span>3. 每个问题标注访谈目的</span></span>
<span class="line"><span>4. 避免引导性问题，使用开放式提问</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><h3 id="_15-2-2-用-ai-生成产品文档" tabindex="-1">15.2.2 用 AI 生成产品文档 <a class="header-anchor" href="#_15-2-2-用-ai-生成产品文档" aria-label="Permalink to “15.2.2 用 AI 生成产品文档”">​</a></h3><p><strong>AI生成PRD框架</strong></p><p>Prompt模板：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一个资深产品经理，擅长撰写结构清晰的PRD。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>请帮我写一个[功能名称]的PRD框架。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 产品背景</span></span>
<span class="line"><span>产品：[产品名称]，[一句话定位]</span></span>
<span class="line"><span>目标用户：[用户描述]</span></span>
<span class="line"><span>当前数据：[DAU/MAU/关键指标]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 功能描述</span></span>
<span class="line"><span>[描述这个功能要做什么，解决什么问题]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># PRD要求包含</span></span>
<span class="line"><span>1. 需求背景与目标</span></span>
<span class="line"><span>2. 目标用户与场景</span></span>
<span class="line"><span>3. 用户故事</span></span>
<span class="line"><span>4. 功能详细描述（含流程图描述）</span></span>
<span class="line"><span>5. 异常情况处理</span></span>
<span class="line"><span>6. 数据埋点方案</span></span>
<span class="line"><span>7. 上线评估标准</span></span>
<span class="line"><span>8. 里程碑与排期建议</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出格式</span></span>
<span class="line"><span>使用Markdown格式，每个大节用二级标题，小节用三级标题。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br></div></div><p>AI生成后，你需要：</p><ol><li>检查逻辑是否完整（AI可能会遗漏异常流程）</li><li>补充具体数值（AI不知道你的具体数据）</li><li>调整语气和风格（AI写的可能太正式或太口语）</li><li>增加业务约束（AI不知道你的技术债和资源限制）</li></ol><p><strong>AI辅助写用户故事</strong></p><p>用户故事是PRD的核心，但很多产品经理写的用户故事太粗糙。AI可以帮你把模糊的需求变成标准的用户故事。</p><p>Prompt模板：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一个敏捷产品经理，擅长撰写标准的用户故事。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>请根据以下需求描述，生成标准的用户故事。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 需求描述</span></span>
<span class="line"><span>[描述你的需求，可以是模糊的]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 用户故事格式</span></span>
<span class="line"><span>作为[角色]，我想[动作]，以便[价值/目的]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 要求</span></span>
<span class="line"><span>1. 每个用户故事遵循INVEST原则（独立、可协商、有价值、可估算、小、可测试）</span></span>
<span class="line"><span>2. 每个用户故事附上验收标准（Given-When-Then格式）</span></span>
<span class="line"><span>3. 如果需求太大，拆分为多个用户故事</span></span>
<span class="line"><span>4. 标注用户故事的优先级（Must/Should/Could/Won&#39;t）</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出格式</span></span>
<span class="line"><span>### 用户故事 [编号]</span></span>
<span class="line"><span>**故事：** 作为[角色]，我想[动作]，以便[价值]</span></span>
<span class="line"><span>**优先级：** Must/Should/Could/Won&#39;t</span></span>
<span class="line"><span>**验收标准：**</span></span>
<span class="line"><span>- Given [前提条件], When [触发动作], Then [期望结果]</span></span>
<span class="line"><span>- Given [前提条件], When [触发动作], Then [期望结果]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br></div></div><p>输出示例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>### 用户故事 US-001</span></span>
<span class="line"><span>**故事：** 作为搜索用户，我想按时间范围筛选搜索结果，以便快速找到最近的内容</span></span>
<span class="line"><span>**优先级：** Must</span></span>
<span class="line"><span>**验收标准：**</span></span>
<span class="line"><span>- Given 用户在搜索结果页, When 用户选择&quot;最近一周&quot;, Then 只显示7天内发布的结果</span></span>
<span class="line"><span>- Given 用户在搜索结果页, When 用户选择自定义时间范围, Then 显示该范围内的结果</span></span>
<span class="line"><span>- Given 搜索结果为空, When 用户调整时间范围, Then 显示提示&quot;未找到匹配结果，请调整时间范围&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 用户故事 US-002</span></span>
<span class="line"><span>**故事：** 作为搜索用户，我想保存搜索条件，以便下次快速使用相同的筛选</span></span>
<span class="line"><span>**优先级：** Should</span></span>
<span class="line"><span>**验收标准：**</span></span>
<span class="line"><span>- Given 用户设置了筛选条件, When 用户点击&quot;保存搜索&quot;, Then 条件保存到&quot;我的搜索&quot;列表</span></span>
<span class="line"><span>- Given 用户有已保存的搜索, When 用户点击某条保存记录, Then 自动填充对应的筛选条件</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p><strong>AI辅助做竞品分析报告</strong></p><p>一份完整的竞品分析报告需要大量信息整理，AI可以帮你搭框架、填内容。</p><p>Prompt模板：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一个产品竞品分析专家，擅长输出结构化的竞品分析报告。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>请帮我撰写一份竞品分析报告。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 分析对象</span></span>
<span class="line"><span>我方产品：[产品名称]，[定位描述]</span></span>
<span class="line"><span>竞品：[竞品1名称]、[竞品2名称]、[竞品3名称]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 分析维度</span></span>
<span class="line"><span>1. 产品定位与目标用户对比</span></span>
<span class="line"><span>2. 核心功能对比（用表格呈现）</span></span>
<span class="line"><span>3. 交互体验对比</span></span>
<span class="line"><span>4. 商业模式对比</span></span>
<span class="line"><span>5. 数据表现对比（如公开数据）</span></span>
<span class="line"><span>6. SWOT分析（针对我方产品）</span></span>
<span class="line"><span>7. 可借鉴的点（Top 3）</span></span>
<span class="line"><span>8. 差异化建议（Top 3）</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出格式</span></span>
<span class="line"><span>使用Markdown格式，每个维度一个章节。</span></span>
<span class="line"><span>功能对比用表格，分析用段落，建议用编号列表。</span></span>
<span class="line"><span>总字数控制在2000字以内。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div><p>输出示例（SWOT部分）：</p><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>优势（S）</td><td>社区氛围好，用户粘性高，内容质量审核严格</td></tr><tr><td>劣势（W）</td><td>搜索功能弱，缺少短视频内容，商业化手段单一</td></tr><tr><td>机会（O）</td><td>短视频赛道仍有增量，AI推荐可提升内容分发效率</td></tr><tr><td>威胁（T）</td><td>竞品A正在强化社区功能，竞品B有更强的算法推荐能力</td></tr></tbody></table><p><strong>AI辅助生成测试用例</strong></p><p>产品经理虽然不写测试代码，但需要提供验收测试场景。AI可以帮你从PRD生成完整的测试用例。</p><p>Prompt模板：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一个QA工程师，擅长从产品需求中设计全面的测试用例。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>请根据以下功能描述，生成测试用例。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 功能描述</span></span>
<span class="line"><span>[粘贴功能描述或PRD片段]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 测试用例要求</span></span>
<span class="line"><span>1. 覆盖正常流程和异常流程</span></span>
<span class="line"><span>2. 覆盖边界条件</span></span>
<span class="line"><span>3. 覆盖兼容性（如适用）</span></span>
<span class="line"><span>4. 每个用例包含：用例编号、测试场景、前置条件、操作步骤、预期结果、优先级</span></span>
<span class="line"><span>5. 按功能模块分组</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出格式</span></span>
<span class="line"><span>| 用例编号 | 测试场景 | 前置条件 | 操作步骤 | 预期结果 | 优先级 |</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><p>输出示例：</p><table tabindex="0"><thead><tr><th>用例编号</th><th>测试场景</th><th>前置条件</th><th>操作步骤</th><th>预期结果</th><th>优先级</th></tr></thead><tbody><tr><td>TC-001</td><td>正常搜索</td><td>用户已登录</td><td>1.输入关键词 2.点击搜索</td><td>显示搜索结果列表</td><td>P0</td></tr><tr><td>TC-002</td><td>空关键词搜索</td><td>用户已登录</td><td>1.搜索框留空 2.点击搜索</td><td>提示&quot;请输入搜索关键词&quot;</td><td>P0</td></tr><tr><td>TC-003</td><td>搜索无结果</td><td>用户已登录</td><td>1.输入无匹配的关键词 2.点击搜索</td><td>显示&quot;未找到相关结果&quot;和建议</td><td>P1</td></tr><tr><td>TC-004</td><td>搜索结果翻页</td><td>搜索结果&gt;20条</td><td>1.执行搜索 2.点击第2页</td><td>正确加载第2页结果</td><td>P1</td></tr><tr><td>TC-005</td><td>特殊字符搜索</td><td>用户已登录</td><td>1.输入<code>&lt;script&gt;alert(1)&lt;/script&gt;</code> 2.点击搜索</td><td>不执行脚本，显示无结果或转义处理</td><td>P0</td></tr></tbody></table><p><strong>AI生成原型说明文档</strong></p><p>Prompt模板：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一个产品经理，擅长撰写原型说明文档。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>请根据以下原型描述，生成原型说明文档。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 原型描述</span></span>
<span class="line"><span>[粘贴你的原型描述或上传原型截图]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 文档要求</span></span>
<span class="line"><span>1. 页面结构说明（每个区域做什么）</span></span>
<span class="line"><span>2. 交互逻辑说明（点击/滑动/长按等操作后的响应）</span></span>
<span class="line"><span>3. 数据字段说明（每个字段含义和格式）</span></span>
<span class="line"><span>4. 异常流程说明（网络错误/空数据/权限不足等）</span></span>
<span class="line"><span>5. 状态说明（不同状态下页面的差异）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h3 id="_15-2-3-ai-在产品设计全流程中的应用" tabindex="-1">15.2.3 AI 在产品设计全流程中的应用 <a class="header-anchor" href="#_15-2-3-ai-在产品设计全流程中的应用" aria-label="Permalink to “15.2.3 AI 在产品设计全流程中的应用”">​</a></h3><p><strong>AI在产品设计全流程中的应用地图</strong></p><table tabindex="0"><thead><tr><th>阶段</th><th>AI能做什么</th><th>推荐工具</th><th>注意事项</th></tr></thead><tbody><tr><td>市场调研</td><td>自动抓取和分析竞品信息</td><td>ChatGPT、Claude</td><td>AI抓取的数据可能过时，需人工核实</td></tr><tr><td>需求分析</td><td>从用户反馈中提取需求</td><td>ChatGPT、自研工具</td><td>AI可能误分类，关键需求人工复核</td></tr><tr><td>产品设计</td><td>生成PRD框架、原型说明</td><td>ChatGPT、Notion AI</td><td>AI生成的只是框架，需人工精修</td></tr><tr><td>原型设计</td><td>生成线框图</td><td>Galileo AI、Uizard</td><td>AI生成的原型只能做参考，细节需调整</td></tr><tr><td>开发协作</td><td>生成技术方案建议</td><td>GitHub Copilot</td><td>技术方案需开发确认可行性</td></tr><tr><td>数据分析</td><td>自动生成分析报告</td><td>ChatGPT、Python+AI</td><td>数据结论需人工判断业务含义</td></tr><tr><td>用户研究</td><td>生成访谈提纲、分析访谈记录</td><td>ChatGPT</td><td>访谈洞察需人工判断真伪</td></tr><tr><td>测试验收</td><td>生成测试用例</td><td>ChatGPT、自研工具</td><td>边界用例需人工补充</td></tr></tbody></table><p>怕浪猫总结了一个&quot;AI辅助产品设计的3-3原则&quot;：</p><p>三分用AI：信息收集、框架生成、初稿撰写，这三类工作放心交给AI。</p><p>三分靠人：需求判断、体验设计、跨团队协调，这三类工作AI帮不上忙。</p><p>三分人机协作：数据分析、文档精修、竞品洞察，这三类工作AI出初稿人来精修。</p><p>剩下一分是什么？是怕浪猫说的&quot;直觉&quot;——产品经理对用户和市场的直觉，这个东西AI学不会。</p><blockquote><p>AI不是来替代你的，而是来&quot;增强&quot;你的。会用AI的产品经理，效率是普通产品经理的3-5倍。</p></blockquote><h3 id="_15-2-4-ai产品设计实战-从0到1设计一个ai助手" tabindex="-1">15.2.4 AI产品设计实战：从0到1设计一个AI助手 <a class="header-anchor" href="#_15-2-4-ai产品设计实战-从0到1设计一个ai助手" aria-label="Permalink to “15.2.4 AI产品设计实战：从0到1设计一个AI助手”">​</a></h3><p>怕浪猫这一节不讲理论，直接带你走一遍完整的AI助手产品设计流程。假设我们要设计一个&quot;AI编程助手&quot;，目标是帮助初中级开发者提高编码效率。</p><p><strong>第一步：需求分析</strong></p><p>先明确三个问题：用户是谁？痛点是什么？AI能解决什么？</p><table tabindex="0"><thead><tr><th>维度</th><th>分析内容</th></tr></thead><tbody><tr><td>目标用户</td><td>1-3年经验的初中级开发者，日常需要写代码、查文档、调试Bug</td></tr><tr><td>核心痛点</td><td>频繁切换工具（编辑器/浏览器/文档）、重复性代码写太多、调试耗时、不熟悉新框架时效率低</td></tr><tr><td>AI能解决的</td><td>代码补全、代码解释、Bug诊断、文档查询、代码重构建议</td></tr><tr><td>AI不能解决的</td><td>架构设计决策（需要经验判断）、性能调优（需要系统理解）、团队协作问题</td></tr></tbody></table><p><strong>第二步：能力定义</strong></p><p>根据需求分析，定义AI助手的核心能力矩阵：</p><table tabindex="0"><thead><tr><th>能力模块</th><th>具体能力</th><th>优先级</th><th>实现难度</th></tr></thead><tbody><tr><td>代码补全</td><td>根据上下文自动补全代码</td><td>P0</td><td>中</td></tr><tr><td>代码解释</td><td>选中代码段，AI解释含义</td><td>P0</td><td>低</td></tr><tr><td>Bug诊断</td><td>分析错误信息，给出修复建议</td><td>P0</td><td>中</td></tr><tr><td>代码生成</td><td>根据自然语言描述生成代码</td><td>P1</td><td>中</td></tr><tr><td>代码重构</td><td>给出重构建议和重构后代码</td><td>P1</td><td>高</td></tr><tr><td>文档问答</td><td>基于官方文档回答技术问题</td><td>P2</td><td>中</td></tr><tr><td>单测生成</td><td>自动生成单元测试代码</td><td>P2</td><td>中</td></tr></tbody></table><p><strong>第三步：Prompt设计</strong></p><p>这是AI产品的核心。每个能力模块都需要精心设计Prompt。怕浪猫以&quot;Bug诊断&quot;能力为例展示完整的Prompt设计过程。</p><p>初版Prompt：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是一个编程助手，用户会给你一段报错信息，请帮用户分析原因并给出修复建议。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个Prompt太笼统了。AI不知道用户用什么语言、什么框架，输出格式也不明确。迭代。</p><p>第二版Prompt：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一个全栈编程助手，擅长诊断和修复代码Bug。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>用户会给你一段错误信息和相关代码，请分析原因并给出修复建议。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 要求</span></span>
<span class="line"><span>1. 先分析错误类型（语法错误/逻辑错误/运行时错误/配置错误）</span></span>
<span class="line"><span>2. 再定位可能的原因（给出Top 3）</span></span>
<span class="line"><span>3. 给出修复方案（包含修复代码）</span></span>
<span class="line"><span>4. 如果有多种修复方式，说明各自的优缺点</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出格式</span></span>
<span class="line"><span>1. 错误类型：[类型]</span></span>
<span class="line"><span>2. 原因分析：[分析]</span></span>
<span class="line"><span>3. 修复方案：[代码+说明]</span></span>
<span class="line"><span>4. 预防建议：[如何避免同类问题]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>第二版好多了，但还缺一些东西。比如用户可能给的信息不全，AI应该主动追问。再迭代。</p><p>第三版（终版）Prompt：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一个全栈编程助手，擅长诊断和修复代码Bug。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>用户会给你错误信息和相关代码，请分析原因并给出修复建议。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 分析步骤</span></span>
<span class="line"><span>1. 解析错误信息，提取关键错误类型和堆栈</span></span>
<span class="line"><span>2. 结合代码上下文，定位错误根因</span></span>
<span class="line"><span>3. 给出Top 3可能原因（按可能性排序）</span></span>
<span class="line"><span>4. 针对最可能的原因给出修复方案</span></span>
<span class="line"><span>5. 提供预防同类问题的建议</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出格式</span></span>
<span class="line"><span>## 错误类型</span></span>
<span class="line"><span>[语法错误/逻辑错误/运行时错误/配置错误/其他]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 原因分析</span></span>
<span class="line"><span>1. [最可能的原因]（可能性：高）</span></span>
<span class="line"><span>2. [次可能的原因]（可能性：中）</span></span>
<span class="line"><span>3. [其他可能的原因]（可能性：低）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 修复方案</span></span>
<span class="line"><span>[修复代码和说明]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 预防建议</span></span>
<span class="line"><span>[如何避免同类问题]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 特殊处理</span></span>
<span class="line"><span>- 如果用户给出的信息不足以判断，列出需要补充的信息</span></span>
<span class="line"><span>- 如果是框架/库的已知问题，附上相关Issue链接</span></span>
<span class="line"><span>- 如果修复方案有风险（如可能影响其他功能），明确标注</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 约束</span></span>
<span class="line"><span>- 修复代码必须与用户的技术栈一致</span></span>
<span class="line"><span>- 不要修改与Bug无关的代码</span></span>
<span class="line"><span>- 如果不确定根因，诚实说明，不要猜测</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br></div></div><p>怕浪猫的Prompt设计心得：好的Prompt就像好的需求文档——角色清晰、任务明确、步骤有序、格式规范、边界清楚、异常处理完备。你写PRD时怎么严谨，写Prompt就怎么严谨。</p><p><strong>第四步：交互设计</strong></p><p>AI助手的交互设计和传统产品不同，核心挑战是&quot;如何让用户信任AI的输出并高效使用&quot;。</p><table tabindex="0"><thead><tr><th>交互场景</th><th>设计方案</th><th>设计理由</th></tr></thead><tbody><tr><td>AI输出代码</td><td>代码高亮+一键复制+差异对比</td><td>用户需要快速使用和验证AI代码</td></tr><tr><td>AI解释代码</td><td>行内标注，悬浮显示解释</td><td>不打断用户阅读代码的节奏</td></tr><tr><td>AI诊断Bug</td><td>错误信息旁边直接显示诊断按钮</td><td>减少用户操作路径</td></tr><tr><td>AI输出不确定</td><td>灰色标注+置信度提示</td><td>让用户知道AI不是100%确定</td></tr><tr><td>AI输出有风险</td><td>黄色警告+需要确认才能执行</td><td>避免AI操作带来不可逆影响</td></tr><tr><td>AI无法回答</td><td>诚实说明+给出替代建议</td><td>维护用户信任，不要编造答案</td></tr><tr><td>用户反馈</td><td>每次AI输出后都有&quot;有用/没用&quot;按钮</td><td>收集反馈用于模型改进</td></tr></tbody></table><p>关键交互原则：</p><p>渐进式展示：不要一次性给用户大量信息。先给结论，用户需要细节时再展开。</p><p>人在回路：高风险操作（如自动修改代码）需要用户确认。AI建议，人决策。</p><p>可解释性：AI给出的建议要附带理由，让用户理解&quot;为什么&quot;，而不是盲从。</p><p><strong>第五步：评估指标</strong></p><p>产品上线前就要定义好评估指标，不然上线后你不知道效果好不好。</p><table tabindex="0"><thead><tr><th>指标类别</th><th>具体指标</th><th>目标值</th><th>评估方式</th></tr></thead><tbody><tr><td>代码补全</td><td>采纳率</td><td>&gt;40%</td><td>代码补全建议被接受的次数/总建议次数</td></tr><tr><td>Bug诊断</td><td>修复成功率</td><td>&gt;60%</td><td>用户反馈&quot;诊断有用&quot;的次数/总诊断次数</td></tr><tr><td>代码解释</td><td>满意度</td><td>&gt;4.0/5.0</td><td>用户评分</td></tr><tr><td>整体效率</td><td>任务完成时间</td><td>降低30%</td><td>有AI vs 无AI的任务完成时间对比</td></tr><tr><td>整体体验</td><td>NPS</td><td>&gt;30</td><td>用户调研</td></tr><tr><td>安全性</td><td>有害代码率</td><td>&lt;0.1%</td><td>AI生成的代码包含安全漏洞的比例</td></tr><tr><td>安全性</td><td>幽觉率</td><td>&lt;5%</td><td>AI编造不存在的API/函数的比例</td></tr></tbody></table><p><strong>第六步：迭代优化</strong></p><p>产品上线后，根据数据持续迭代。怕浪猫总结了一个AI产品的迭代节奏：</p><table tabindex="0"><thead><tr><th>阶段</th><th>时间</th><th>重点</th><th>关键动作</th></tr></thead><tbody><tr><td>冷启动期</td><td>上线1-2周</td><td>收集真实数据，不做大改</td><td>监控核心指标，收集用户反馈</td></tr><tr><td>快速迭代期</td><td>上线3-6周</td><td>根据数据修复明显问题</td><td>优化Prompt、调整输出格式、修复高频Bad Case</td></tr><tr><td>稳定优化期</td><td>上线7-12周</td><td>提升核心指标，拓展能力</td><td>A/B测试Prompt优化、新增能力模块、优化交互体验</td></tr><tr><td>精细化运营期</td><td>上线3个月+</td><td>长尾场景覆盖，个性化</td><td>用户分群优化、场景化Prompt、多模型策略</td></tr></tbody></table><p>迭代中最重要的事情是Bad Case分析。每周选出10个用户反馈&quot;没用&quot;的案例，逐个分析原因：</p><table tabindex="0"><thead><tr><th>Bad Case类型</th><th>占比</th><th>处理方式</th></tr></thead><tbody><tr><td>Prompt理解偏差</td><td>30%</td><td>优化Prompt，增加示例</td></tr><tr><td>模型能力不足</td><td>25%</td><td>换用更强的模型，或增加RAG检索</td></tr><tr><td>用户输入不清</td><td>20%</td><td>优化交互引导，提供输入模板</td></tr><tr><td>边界场景</td><td>15%</td><td>增加边界处理逻辑</td></tr><tr><td>不合理期望</td><td>10%</td><td>优化产品说明，管理用户预期</td></tr></tbody></table><p>怕浪猫最后说一句：设计AI产品和设计传统产品最大的区别不是方法论变了，而是你需要多考虑一个维度——&quot;AI的不确定性&quot;。传统产品你设计的是确定性流程，AI产品你设计的是&quot;AI做对了怎么办、AI做错了怎么办、AI不确定怎么办&quot;这三种情况的应对方案。把这三个问题想清楚，你的AI产品就不会差。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to “本章小结”">​</a></h2><p>AI时代，产品经理不会被替代，但会被&quot;会用AI的产品经理&quot;替代。掌握AI工具的使用能力、AI产品的设计能力、AI伦理与风险管理能力、提示词工程能力、AI产品评估能力，是AI时代产品经理的必修课。</p><table tabindex="0"><thead><tr><th>本章核心知识点</th><th>一句话总结</th></tr></thead><tbody><tr><td>AI能替代的</td><td>重复性、规则性、可描述的工作</td></tr><tr><td>AI不能替代的</td><td>创造性、判断性、责任性的工作</td></tr><tr><td>新能力要求</td><td>AI工具使用+AI产品设计+AI伦理+提示词工程+AI产品评估</td></tr><tr><td>提示词工程</td><td>Prompt设计要像写PRD一样严谨——角色、任务、背景、格式、约束缺一不可</td></tr><tr><td>AI产品评估</td><td>三层评估：模型能力、产品体验、业务价值</td></tr><tr><td>AI辅助需求分析</td><td>从反馈提取需求、竞品对比、RICE排序、访谈提纲</td></tr><tr><td>AI生成文档</td><td>PRD框架、用户故事、竞品分析报告、测试用例、原型说明</td></tr><tr><td>AI全流程应用</td><td>调研→分析→设计→开发→分析→研究</td></tr><tr><td>AI产品设计实战</td><td>需求分析→能力定义→Prompt设计→交互设计→评估指标→迭代优化</td></tr></tbody></table><p>觉得有用？收藏起来，下次用AI辅助产品设计时直接照抄Prompt。</p><p>你认为AI会替代产品经理吗？评论区说说你的看法。</p><p>关注怕浪猫，下期我们讲&quot;产品人生与职业规划&quot;——产品经理的职业发展路径，怕浪猫给你建议。</p><p>系列进度 15/16</p><p><strong>下章预告：</strong> 第16章是收官之作。产品经理的职业发展路径是什么？怎么从初级产品经理成长到产品总监？怕浪猫用5年产品经理经验，给你最真实的建议。</p>`,147)])])}const o=n(l,[["render",e]]);export{h as __pageData,o as default};
